+
+        // Burst phase: actual >> predicted, but marked as burst_outlier.
+        for _ in 0..5 {
+            guard.observe(CalibrationObservation {
+                predicted_rate: 100.0,
+                actual_rate: 50_000.0,
+                predicted_tte: 300.0,
